+func TestUpdateAgentStats_Cumulative(t *testing.T) {
+	breakdown := make(map[string]AgentStats)
+
+	updateAgentStats(breakdown, "claude", 2, 0, 0)
+	updateAgentStats(breakdown, "claude", 0, 3, 150)
